interface Observer { void update(String message); }
class ConcreteObserver implements Observer {
    private String name;
    public ConcreteObserver(String name){ this.name=name; }
    public void update(String message){ System.out.println(name+" received message: "+message); }
}
class Subject {
    private List<Observer> observers=new ArrayList<>();
    private String message;
    public void addObserver(Observer o){ observers.add(o); }
    public void removeObserver(Observer o){ observers.remove(o); }
    public void setMessage(String message){ this.message=message; notifyObservers(); }
    public void notifyObservers(){ for(Observer o: observers){ o.update(message); } }
}
public class ObserverPatternExample {
    public static void main(String[] args){
        Subject subject=new Subject();
        Observer o1=new ConcreteObserver("Observer 1");
        Observer o2=new ConcreteObserver("Observer 2");
        subject.addObserver(o1);
        subject.addObserver(o2);
        subject.setMessage("Hello, Observers");
        subject.removeObserver(o1);
        subject.setMessage("Observer 1 is no longer receiving updates.");
    }
}

